import{_ as o,o as i,c as a,ah as r}from"./chunks/framework.Bi9enVNS.js";const p=JSON.parse('{"title":"架构与数据流","description":"","frontmatter":{},"headers":[],"relativePath":"intro/architecture.md","filePath":"intro/architecture.md","lastUpdated":1774205896000}'),t={name:"intro/architecture.md"};function l(c,e,d,n,s,u){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="架构与数据流" tabindex="-1">架构与数据流 <a class="header-anchor" href="#架构与数据流" aria-label="Permalink to &quot;架构与数据流&quot;">​</a></h1><p>VLT 当前是一套非常明确的单体参考实现：摄取、校验、归一化、内存存储、HTTP 查询和前端工作台都在同一个仓库中。</p><h2 id="端到端路径" tabindex="-1">端到端路径 <a class="header-anchor" href="#端到端路径" aria-label="Permalink to &quot;端到端路径&quot;">​</a></h2><ol><li>调用方按 <code>ingest.v1.UploadLogsRequest</code> 组织日志批次。</li><li>发送到 <code>POST /v1/logs</code>，并携带 <code>Authorization: Bearer &lt;token&gt;</code>。</li><li>服务端读取请求体，处理 <code>Content-Encoding</code>，再按 <code>Content-Type</code> 解码。</li><li>执行批次级校验，再执行记录级校验。</li><li>对通过校验的记录做归一化，生成 <code>NormalizedLogRecord</code>。</li><li>写入内存存储。</li><li>前端或其他调用方通过查询接口读取日志、Trace、Timeline、Topology、Sources。</li></ol><h2 id="主要模块" tabindex="-1">主要模块 <a class="header-anchor" href="#主要模块" aria-label="Permalink to &quot;主要模块&quot;">​</a></h2><div class="vlt-source-list"><div><strong>协议层</strong><span><code>proto/vlt/common/v1</code>、<code>proto/vlt/logs/v1</code>、<code>proto/vlt/ingest/v1</code></span></div><div><strong>摄取层</strong><span><code>internal/ingest</code> 负责解码、校验、鉴权、归一化、幂等缓存。</span></div><div><strong>HTTP API</strong><span><code>internal/api/http.go</code> 暴露摄取与查询路由，并处理 CORS。</span></div><div><strong>存储层</strong><span><code>internal/store/memory</code> 保存归一化记录并提供聚合查询。</span></div></div><h2 id="归一化之后的核心实体" tabindex="-1">归一化之后的核心实体 <a class="header-anchor" href="#归一化之后的核心实体" aria-label="Permalink to &quot;归一化之后的核心实体&quot;">​</a></h2><ul><li><code>NormalizedLogRecord</code>：日志查询与 Trace 聚合的统一基础记录</li><li><code>TraceTimelineResponse</code>：以 <code>source_fingerprint</code> 为 lane 的时间线视图</li><li><code>TraceTopologyResponse</code>：由相邻来源段推导出的节点/边视图</li><li><code>SourceGroup</code>：供来源视图使用的树形聚合结构</li></ul><h2 id="关键推导点" tabindex="-1">关键推导点 <a class="header-anchor" href="#关键推导点" aria-label="Permalink to &quot;关键推导点&quot;">​</a></h2><ul><li>有效来源优先使用 <code>LogRecord.source</code>，否则回退到批次 <code>default_source</code></li><li><code>source_fingerprint</code> 由 <code>project + environment + source_type + source_name + instance_id</code> 哈希得出</li><li>timeline 按 <code>source_fingerprint</code> 聚合</li><li>topology 会先折叠连续相同 <code>source_fingerprint</code> 的片段，再从相邻片段生成边</li></ul><h2 id="设计取舍" tabindex="-1">设计取舍 <a class="header-anchor" href="#设计取舍" aria-label="Permalink to &quot;设计取舍&quot;">​</a></h2><ul><li>选择内存存储，优先降低参考实现复杂度</li><li>选择单一 HTTP 上传入口，优先把协议行为做清楚</li><li>选择显式来源建模，优先解决“同一 Trace 下多来源日志如何组织”的问题</li></ul><h2 id="事实来源" tabindex="-1">事实来源 <a class="header-anchor" href="#事实来源" aria-label="Permalink to &quot;事实来源&quot;">​</a></h2><ul><li><code>internal/api/http.go</code></li><li><code>internal/ingest/decode.go</code></li><li><code>internal/ingest/normalize.go</code></li><li><code>internal/store/store.go</code></li><li><code>internal/store/memory/memory.go</code></li></ul>',14)])])}const g=o(t,[["render",l]]);export{p as __pageData,g as default};
